python3 -c "
import json
with open('.fleet/tasks/task-bayes-net-graph-001/worker-output.jsonl') as f:
    for i, line in enumerate(f):
        try:
            obj = json.loads(line)
            if obj.get('type') == 'assistant':
                content = obj.get('message', {}).get('content', [])
                for block in content:
                    if block.get('type') == 'tool_use' and block.get('name') == 'Write':
                        inp = block.get('input', {})
                        if 'analysis' in inp.get('file_path', '') or 'test' in str(inp.get('content', ''))[:200].lower():
                            print(f'Line {i}: Writing to {inp.get(\"file_path\", \"\")}')
                            print(inp.get('content', '')[:2000])
                            print('---')
        except:
